0; sm = Math.min(sm, now); // the block spans FROM THE TIMER'S START → now+N: reality and plan become ONE linked thing (the wide matched bar covers the whole lived stretch, the dock reads ON PLAN instantly — no orphaned pre-tap sliver, no boundary-minute lag)\n      blocks(k).push({ id: uid(), time: pad(Math.floor((sm % 1440) / 60)) + \":\" + pad(sm % 60), mins: (now - sm) + mins, title: t.title, prio: 2, color: t.color || (DOM[dom] || DOM.focus).c, catK: t.catK || null, domain: dom, done: false });\n      t.commit = Math.round((Date.now() - t.start) / 60000) + mins; t._commitHit = false; // the 1s loop's \"done — tap to claim\" fires when the committed stretch elapses\n      reflow(k); save(); renderLiveTracker(); renderToday(); renderTrackerFull();\n      toast(\"✦ planned — yours till \" + fmt((now + mins) % 1440));\n    }, [5, 10, 15, 30, 60, 120], { icon: \"ti-arrows-shuffle\", label: \"Switch activity\", fn: function () { tfPickTrack(\"Switch to?\"); } }); // G12 (David on device, v801): the button reads \"Make a plan\" — it offers a TIME for the CURRENT activity (never a new picker); switching activities is the one secondary option inside this same menu\n  }\n  function tfClaim() { var cb = claimableBlock(); if (!cb) { S._claimDismissed = true; renderTrackerFull(); return; } // collect the gap as a real log, reward it, then keep tracking the same activity forward (David 2026-06-27)\n    var b = cb.block, dom = domainOf(b), D = DOM[dom] || DOM.focus, gapMin = Math.max(1, logicalNowMin() - cb.gapStartMin), sd = new Date(); sd.setHours(0, 0, 0, 0); sd = new Date(sd.getTime() + cb.gapStartMin * 60000);\n    logs(todayK()).push({ id: uid(), time: pad(sd.getHours()) + \":\" + pad(sd.getMinutes()), title: b.title, mins: gapMin, catK: b.catK, color: b.color || D.c, habitId: b.habitId || null }); // the welcome-back WRITE-PATH: heal the gap\n    earn(Math.max(4, Math.round(gapMin / 3)), { catK: b.catK }); bumpStreak(); S._claimDismissed = false; save();\n    var nt = startTrackerNow(); assignTimer(nt, { title: b.title, color: b.color || D.c, catK: b.catK }); maybeCelebrateTrack(nt); renderLiveTracker(); renderToday(); renderTrackerFull(); // continue forward\n  }\n  function tfClaimDismiss() { S._claimDismissed = true; save(); renderTrackerFull(); } // \"not mine\" → clear the claim, fall through to idle/night\n  function tfNightBreathe() { if (typeof breathwork === \"function\") breathwork(4); else toast(\"rest — I've got the morning.\"); } // calm chip: a 4-cycle breath, or a gentle line\n  // ===== ONE shared decision matrix (David 2026-06-28) =====\n  // The SINGLE source of truth for what controls a tracker state offers. Both the EXPANDED ring (renderTFControls)\n  // AND the FOLDED dock seg (renderLiveDock) render from this, so the two surfaces ALWAYS show the same actions\n  // (same labels, same handlers, same order) → the .ld-seg ↔ #tfCtrls morph pairs the buttons 1:1.\n  // Returns an ordered array of { icon, label, fn, primary }. Exactly one entry is primary (= the big #tfDone button\n  // expanded / the play-stop circle in the folded dock). The rest are the secondary seg/row actions.\n  function trackerControls(state) {\n    switch (state) {\n      case \"claim\": { // §12 composition law: the claim is a hero + two doors — solid wears the block's colour, the escape whispers\n        var _cbk = null; try { _cbk = trackerState().block; } catch (e) {}\n        var _cdm = _cbk ? (DOM[domainOf(_cbk)] || DOM.focus) : DOM.focus;\n        return [{ icon: \"ti-circle-check\", label: \"Claim it\", fn: tfClaim, primary: true, finish: \"solid\", c: _cdm.c, ink: _cdm.ink },\n                { icon: \"ti-x\", label: \"Not mine\", fn: tfClaimDismiss, finish: \"ghost\" }];\n      }\n      case \"night\":\n        return [{ icon: \"ti-wind\", label: \"Breathe with me\", fn: tfNightBreathe, primary: true, finish: \"solid\", c: \"#9a8cff\", ink: \"#1c1030\" },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: closeTrackerFull, finish: \"ghost\" }];\n      case \"idle\": { // §12 COCKPIT FRAME (David's upload 07): THREE FIXED DOORS — pink Track now / striped Plan+track next / ghost Plan my day; the docked time sheet handles the next block's duration\n        var n = nextPlannedBlock(todayK());\n        if (n) {\n          return [{ icon: \"ti-player-play\", label: \"Track now\", fn: playFirst, primary: true, finish: \"solid\", c: \"#ff5fa8\", ink: \"#4a1126\" },\n                  { icon: \"ti-calendar-plus\", label: \"Plan + track next\", fn: function () { startNextNow(n); }, finish: \"striped\", c: \"#36b3f0\", ink: \"#08283c\", tag: n.title }, // RUN-1 mock 1: the striped door NAMES its block\n                  { icon: \"ti-map-2\", label: \"Plan my day\", fn: function () { closeTrackerFull(); try { shapeFlow(todayK()); } catch (e) {} }, finish: \"ghost\" }]; }\n        return [{ icon: \"ti-player-play\", label: \"Track now\", fn: playFirst, primary: true, finish: \"solid\", c: \"#ff5fa8\", ink: \"#4a1126\" },\n                { icon: \"ti-map-2\", label: \"Plan my day\", fn: function () { closeTrackerFull(); try { shapeFlow(todayK()); } catch (e) {} }, finish: \"striped\", c: \"#36b3f0\", ink: \"#08283c\", sub: \"3 tasks — 60 seconds\" }]; // RUN-1 mock 2: Plan-my-day sells its real cost. G11 play-first: the app's main verb is the hero\n      }\n      case \"break\":\n        return [{ icon: \"ti-player-play-filled\", label: \"Resume\", fn: tfResumeBreak, primary: true },\n                { icon: \"ti-plus\", label: \"+5 min\", fn: function () { tfBreakPlus(5); } },\n                { icon: \"ti-x\", label: \"End break\", fn: tfEndBreak }];\n      case \"breakup\":\n        return [{ icon: \"ti-arrow-back-up\", label: \"Back to it\", fn: tfResumeBreak, primary: true },\n                { icon: \"ti-plus\", label: \"+5 min\", fn: function () { tfBreakPlus(5); } },\n                { icon: \"ti-x\", label: \"End\", fn: tfEndBreak }];\n      case \"onplan\": // RUN-1 mock 3: green solid door + ghost 2-up row. The colored title pill IS the switch (David 2026-06-27)\n        return [{ icon: \"ti-check\", label: \"Done — count it\", fn: tfDone, primary: true, finish: \"solid\", c: \"#28cf86\", ink: \"#07351f\" },\n                { icon: \"ti-player-pause\", label: \"Pause\", fn: tfStartBreak, half: true },\n                { icon: \"ti-refresh\", label: \"Reschedule\", fn: tfReplan, half: true }];\n      // ===== COCKPIT GUIDED MODES (CKPT-3, David 2026-06-28): same {icon,label,fn,primary} shape → renderTFControls AND renderDockSeg render them + the morph pairs them 1:1. Wave-1 = minimal [Done -> exitStage]; real beat-controls land in CKPT-5/6/8. =====\n      case \"journal\":\n        return [{ icon: \"ti-circle-check\", label: \"Save\", fn: function () { exitStage(true); }, primary: true },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: function () { exitStage(false); } }]; // Close = abandon: stop the timer WITHOUT writing a journal entry, ring un-corners\n      case \"journey\": // the next-step card owns its primary CTA (in #tfStageBody); the bar just offers an escape + a do-anytime track door (never traps)\n        return [{ icon: \"ti-list-search\", label: \"Just track instead\", fn: function () { TF_MODE = null; TF_MODE_USERSET = true; renderTrackerFull(); }, primary: true },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: closeTrackerFull }];\n      case \"pm-mirror\": case \"pm-ask\": case \"am-greet\":\n        return [{ icon: \"ti-circle-check\", label: \"Done\", fn: function () { exitStage(true); }, primary: true },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: closeTrackerFull }];\n      case \"sleepmath\": case \"rx\":\n        return [{ icon: \"ti-circle-check\", label: \"Done\", fn: function () { exitStage(false); }, primary: true },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: closeTrackerFull }];\n      case \"tool\":\n        return [{ icon: \"ti-chevron-down\", label: \"Close\", fn: closeTrackerFull, primary: true, finish: \"ghost\" }]; // §12 frame: Close is an EXIT, never the big green GO — ghost door; the header's circle-X is the frame's close\n      // ===== AM / PM bookend controls (David 2026-06-28): Save commits the bookend record + GENTLE gated celebrate; Close abandons (no write), ring un-corners. Added at the END so sibling-mode merges stay trivial. =====\n      case \"pm\": // MULTI-BEAT: primary ADVANCES the beat (pmAdvance commits on the final 'close' beat); Close abandons (no write), ring un-corners\n        return [{ icon: \"ti-arrow-right\", label: pmPrimaryLabel(), fn: pmAdvance, primary: true },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: function () { exitStage(false); } }];\n      case \"am\":\n        return [{ icon: \"ti-circle-check\", label: \"Save\", fn: function () { exitStage(true); }, primary: true },\n                { icon: \"ti-chevron-down\", label: \"Close\", fn: function () { exitStage(false); } }];\n      default: { // OFF-PLAN while tracking (David 2026-07-02, C7+D2): the fusion tap LEADS — \"Keep going N more minutes\" turns the live track into a plan in one move. Pause is table-stakes (it only existed on-plan — that's why it was never seen). Replan/Create + Stop stay. Drift keeps Replan primary (planning-the-drift makes no sense — the way back leads).\n        var _dr = false; try { _dr = !!trackerState().drift; } catch (e) {}\n        var mk = tfHasPlan() ? { icon: \"ti-arrows-shuffle\", label: \"Replan\", fn: tfReplan } : { icon: \"ti-calendar-plus\", label: \"Create plan\", fn: tfCreatePlan };\n        if (_dr) return [{ icon: mk.icon, label: mk.label, fn: mk.fn, primary: true, finish: \"striped\", c: \"#36b3f0\", ink: \"#08283c\" },\n                         { icon: \"ti-player-pause\", label: \"Pause\", fn: tfStartBreak, half: true },\n                         { icon: \"ti-player-stop\", label: \"Stop\", fn: tfDone, half: true }];\n        return [{ icon: \"ti-calendar-plus\", label: \"Make a plan\", fn: tfKeepGoing, primary: true, finish: \"striped\", c: \"#36b3f0\", ink: \"#08283c\" },\n                { icon: \"ti-player-pause\", label: \"Pause\", fn: tfStartBreak, half: true },\n                { icon: \"ti-player-stop\", label: \"Stop\", fn: tfDone, half: true }]; // RUN-1 mock 4: striped-blue \"Составить план\" fusion door + ghost 2-up [Пауза | Стоп]. G12 (v801): \"Make a plan\" = a time for what you're already doing.\n      }\n    }\n  }\n  function renderTFControls(state) { var c = el(\"tfCtrls\"); if (!c) return; c.innerHTML = \"\";\n    var ctrls = trackerControls(state);\n    if (ctrls.some(function (x) { return x.finish; })) { // GRAND BUILD F: door mode — stacked full-width chunky buttons, finish = hierarchy (solid -> striped -> ghost). RUN-1: optional right-tag (names the block), optional cost sub-line, and a ghost half-row (x.half)\n      var halves = [];\n      ctrls.forEach(function (x) {\n        if (x.half) { halves.push(x); return; }\n        var cls = \"tf-door tf-door-\" + (x.finish || \"ghost\") + (x.tag ? \" has-tag\" : \"\") + (x.sub ? \" has-sub\" : \"\");\n        var bn = add(c, \"button\", cls);\n        if (x.tag) { bn.innerHTML = '<span class=\"tf-door-lead\"><i class=\"ti ' + x.icon + '\"></i><span>' + x.label + '</span></span><span class=\"tf-door-tag\" style=\"color:' + (x.ink || \"#08283c\") + '\">' + esc(x.tag) + '</span>'; }\n        else if (x.sub) { bn.innerHTML = '<span class=\"tf-door-lead\"><i class=\"ti ' + x.icon + '\"></i><span>' + x.label + '</span></span><span class=\"tf-door-sub\">' + esc(x.sub) + '</span>'; }\n        else { bn.innerHTML = '<i class=\"ti ' + x.icon + '\"></i> ' + x.label; }\n        if (x.finish === \"solid\") { bn.style.background = x.c; bn.style.color = x.ink; }\n        else if (x.finish === \"striped\") { bn.style.background = tfStripe(x.c); bn.style.color = x.ink; }\n        bn.onclick = x.fn;\n      });\n      if (halves.length) { var row = add(c, \"div\", \"tf-row\"); halves.forEach(function (x) { var bn = add(row, \"button\", \"tf-door tf-door-ghost\"); bn.style.flex = \"1\"; bn.style.minHeight = \"48px\"; bn.innerHTML = '<i class=\"ti ' + x.icon + '\"></i> ' + x.label; bn.onclick = x.fn; }); }\n      return;\n    }\n    var prim = ctrls.filter(function (x) { return x.primary; }), sec = ctrls.filter(function (x) { return !x.primary; });\n    prim.forEach(function (x) { var bn = add(c, \"button\", \"tf-b tf-done\"); bn.innerHTML = '<i class=\"ti ' + x.icon + '\"></i>' + x.label; bn.onclick = x.fn; });\n    if (sec.length) { var row = add(c, \"div\", \"tf-row\"); sec.forEach(function (x) { var bn = add(row, \"button\", \"tf-b\"); bn.innerHTML = '<i class=\"ti ' + x.icon + '\"></i>' + x.label; bn.onclick = x.fn; }); }\n  }\n  // ---- ONBOARDING (mockups 041/043, §8): guardian → vibe → gender+age → life-stage → prefill bento → goals → rhythm → world born ----\n  var LIFESTAGES = [\n    { k: \"student\", l: \"Student\", ti: \"ti-backpack\", c: \"#36b3f0\", occ: \"student\" }, { k: \"parent\", l: \"Parent\", ti: \"ti-baby-carriage\", c: \"#ff5fa0\", occ: \"other\" },\n    { k: \"founder\", l: \"Founder\", ti: \"ti-rocket\", c: \"#b07aff\", occ: \"founder\" }, { k: \"employee\", l: \"9-to-5 job\", ti: \"ti-briefcase\", c: \"#7f9bc4\", occ: \"office\" },\n    { k: \"freelancer\", l: \"Freelancer\", ti: \"ti-device-laptop\", c: \"#34d39a\", occ: \"dev\" }, { k: \"creative\", l: \"Creative\", ti: \"ti-palette\", c: \"#ffc83d\", occ: \"artist\" },\n    { k: \"developer\", l: \"Developer\", ti: \"ti-code\", c: \"#36b3f0\", occ: \"dev\" }, { k: \"writer\", l: \"Writer\", ti: \"ti-pencil\", c: \"#b07aff\", occ: \"writer\" },\n    { k: \"caregiver\", l: \"Caregiver\", ti: \"ti-heart-handshake\", c: \"#2ab8c4\", occ: \"other\" }, { k: \"manager\", l: \"Manager\", ti: \"ti-users\", c: \"#7f9bc4\", occ: \"office\" },\n    { k: \"teacher\", l: \"Teacher\", ti: \"ti-school\", c: \"#34d39a\", occ: \"office\" }, { k: \"healthcare\", l: \"Healthcare\", ti: \"ti-stethoscope\", c: \"#ff5fa0\", occ: \"office\" },\n    { k: \"sales\", l: \"Sales / Biz\", ti: \"ti-trending-up\", c: \"#ff8a3a\", occ: \"founder\" }, { k: \"service\", l: \"Service / Hospitality\", ti: \"ti-coffee\", c: \"#ff8a3a\", occ: \"office\" },\n    { k: \"trades\", l: \"Trades / Hands-on\", ti: \"ti-tools\", c: \"#7f9bc4\", occ: \"office\" }, { k: \"athlete\", l: \"Athlete\", ti: \"ti-run\", c: \"#ff8a3a\", occ: \"other\" },\n    { k: \"musician\", l: \"Musician\", ti: \"ti-music\", c: \"#b07aff\", occ: \"artist\" }, { k: \"filmmaker\", l: \"Filmmaker\", ti: \"ti-movie\", c: \"#b07aff\", occ: \"artist\" }, { k: \"jobseeker\", l: \"Job-seeking\", ti: \"ti-search\", c: \"#ffc83d\", occ: \"other\" },\n    { k: \"remote\", l: \"Remote worker\", ti: \"ti-home\", c: \"#34d39a\", occ: \"dev\" }, { k: \"retired\", l: \"Retired\", ti: \"ti-umbrella\", c: \"#2ab8c4\", occ: \"other\" },\n    { k: \"homemaker\", l: \"Homemaker\", ti: \"ti-home-cog\", c: \"#ff5fa0\", occ: \"other\" }, { k: \"figuring\", l: \"Figuring it out\", ti: \"ti-compass\", c: \"#ff8a3a\", occ: \"other\" }\n  ];\n  var VIBES2 = [ { k: \"thriving\", l: \"Thriving\", ti: \"ti-flame\", c: \"#34d39a\" }, { k: \"coasting\", l: \"Coasting\", ti: \"ti-windmill\", c: \"#ffc83d\" }, { k: \"stuck\", l: \"Stuck\", ti: \"ti-anchor\", c: \"#7f9bc4\" }, { k: \"overwhelmed\", l: \"Overwhelmed\", ti: \"ti-urgent\", c: \"#c4607f\" } ];\n  var GOAL_SEED = [ { l: \"Make art\", d: \"create\", ti: \"ti-palette\" }, { l: \"Grow my business\", d: \"focus\", ti: \"ti-briefcase\" }, { l: \"Get fit\", d: \"move\", ti: \"ti-barbell\" }, { l: \"Learn a skill\", d: \"create\", ti: \"ti-bulb\" }, { l: \"Read more\", d: \"play\", ti: \"ti-book\" }, { l: \"Save money\", d: \"focus\", ti: \"ti-coin\" }, { l: \"Sleep better\", d: \"restore\", ti: \"ti-moon\" }, { l: \"Find love\", d: \"connect\", ti: \"ti-heart\" }, { l: \"Eat healthier\", d: \"nourish\", ti: \"ti-apple\" }, { l: \"Quit a bad habit\", d: \"drift\", ti: \"ti-ban\" }, { l: \"Grow my audience\", d: \"create\", ti: \"ti-users\" }, { l: \"Feel calmer\", d: \"restore\", ti: \"ti-wind\" }, { l: \"Clean my home\", d: \"upkeep\", ti: \"ti-home\" }, { l: \"Lose weight\", d: \"move\", ti: \"ti-scale\" }, { l: \"Make music\", d: \"create\", ti: \"ti-music\" }, { l: \"Make videos\", d: \"create\", ti: \"ti-video\" }, { l: \"Write a book\", d: \"create\", ti: \"ti-book\" }, { l: \"Make money\", d: \"focus\", ti: \"ti-cash\" } ];\n  var EXTRAS2 = [\"Get coffee\", \"Snack\", \"Water\", \"Stretch\", \"Text back\", \"Tidy 5m\", \"Vitamins\", \"Skincare\"];\n  function stageSuggest(age) { return (age === \"teens\" || age === \"20s\") ? \"student\" : age === \"30s\" ? \"founder\" : (age === \"40s\" || age === \"50s\") ? \"employee\" : \"figuring\"; }\n  var STAGE_BASE = { move: [\"Walk\", \"Gym\"], nourish: [\"Breakfast\", \"Lunch\", \"Cook\"], connect: [\"Call\", \"Friends\"], play: [\"Read\"], restore: [\"Sleep\", \"Meditate\"], upkeep: [\"Shower\", \"Tidy\"] };\n  var STAGE_EXTRA = {\n    student: [[\"Study\", \"focus\"], [\"Deep work\", \"focus\"], [\"Assignment\", \"focus\"], [\"Group work\", \"connect\"]],\n    parent: [[\"Family\", \"connect\"], [\"Play with kids\", \"connect\"], [\"Meal prep\", \"nourish\"], [\"Errands\", \"upkeep\"], [\"Laundry\", \"upkeep\"]],\n    founder: [[\"Deep work\", \"focus\"], [\"Claude code\", \"focus\"], [\"Outreach\", \"focus\"], [\"Plan\", \"focus\"]],\n    employee: [[\"Deep work\", \"focus\"], [\"Meetings\", \"focus\"], [\"Email\", \"focus\"], [\"Commute\", \"upkeep\"]],\n    freelancer: [[\"Deep work\", \"focus\"], [\"Programming\", \"focus\"], [\"Invoice\", \"focus\"], [\"Outreach\", \"focus\"]],\n    creative: [[\"Draw\", \"create\"], [\"Paint\", \"create\"], [\"Make art\", \"create\"], [\"Design\", \"create\"]],\n    developer: [[\"Code\", \"focus\"], [\"Claude code\", \"focus\"], [\"Debug\", \"focus\"], [\"Programming\", \"focus\"]],\n    writer: [[\"Writing\", \"create\"], [\"Research\", \"focus\"], [\"Edit\", \"create\"]],\n    caregiver: [[\"Help\", \"connect\"], [\"Errands\", \"upkeep\"], [\"Appointments\", \"upkeep\"], [\"Journal\", \"restore\"]],\n    manager: [[\"Meetings\", \"focus\"], [\"Email\", \"focus\"], [\"Plan\", \"focus\"], [\"Calls\", \"connect\"]],\n    teacher: [[\"Lesson plan\", \"focus\"], [\"Grade\", \"focus\"], [\"Teach\", \"connect\"]],\n    healthcare: [[\"Shift\", \"focus\"], [\"Patients\", \"connect\"], [\"Notes\", \"focus\"]],\n    sales: [[\"Outreach\", \"focus\"], [\"Calls\", \"connect\"], [\"Close deal\", \"focus\"]],\n    service: [[\"Shift\", \"focus\"], [\"Customers\", \"connect\"]],\n    trades: [[\"Job site\", \"focus\"], [\"Build\", \"create\"], [\"Tools\", \"upkeep\"]],\n    athlete: [[\"Train\", \"move\"], [\"Gym\", \"move\"], [\"Recovery\", \"restore\"], [\"Stretch\", \"move\"]],\n    musician: [[\"Practice\", \"create\"], [\"Make music\", \"create\"], [\"Perform\", \"create\"]],\n    filmmaker: [[\"Edit footage\", \"create\"], [\"Write script\", \"create\"], [\"Film\", \"create\"], [\"Post a video\", \"create\"]],\n    jobseeker: [[\"Apply\", \"focus\"], [\"Network\", \"connect\"], [\"Study\", \"focus\"]],\n    remote: [[\"Deep work\", \"focus\"], [\"Meetings\", \"focus\"], [\"Email\", \"focus\"]],\n    retired: [[\"Walk\", \"move\"], [\"Garden\", \"play\"], [\"Hobby\", \"play\"]],\n    homemaker: [[\"Meal prep\", \"nourish\"], [\"Clean\", \"upkeep\"], [\"Laundry\", \"upkeep\"], [\"Errands\", \"upkeep\"]],\n    figuring: [[\"Journal\", \"restore\"], [\"Explore\", \"play\"], [\"Study\", \"focus\"]]\n  };\n  // (placementQuestions removed 2026-07-03 — orphaned survey, zero call sites; behavior-evidence chapterUnlockCheck() already places practicing users without self-report. watchConfirmTick keeps handling any legacy seeded entries.)\n  // FRONT-DOOR REWRITE (David 2026-07-02, EPIC-AUDIT Day 2-3): 6 beats, ~90 seconds — showman → pact → one profiling beat → the task → the coin → the seed.\n  // Cut: gender/age/roles/rhythm/goal-picker screens (founder hand-loads those for the sister launch). Kept: ob-ov/ob-card scaffold, chip machinery, progress bar.\n  function onboard() {\n    var data = { vibe: \"\", energy: null, messRoom: \"\", block: \"\", pactAt: null, taskDone: false, seeded: false };\n    var step = 0, STEPS = 7, advT = null; // 0-1 showman · 2 vibe (answered aloud) · 3 the task (sized by vibe) + room re-home · 4 blocker blessing · 5 pact (after the gift) · 6 the seed — FIRST-DAY REWIRE (David 2026-07-03: every answer must visibly change the next beat; the clipboard is dead)\n    var ov = add(document.body, \"div\", \"ob-ov\"), card = add(ov, \"div\", \"ob-card\");\n    var bar = add(card, \"div\", \"ob-bar\"), barDs = []; for (var _bi = 0; _bi < STEPS; _bi++) barDs.push(add(bar, \"i\")); // §12 frame 12: course-style dashes, one per beat\n    var body = add(card, \"div\", \"ob-body\"), foot = add(card, \"div\", \"ob-foot\");\n    function chip(p, label, on, color, ink) { var s = add(p, \"span\", \"ob-ch\" + (on ? \" on\" : \"\")); if (color) { s.style.background = on ? color : mixDark(color); s.style.color = on ? (ink || \"#160510\") : color; } s.innerHTML = label; return s; }\n    function next() { clearTimeout(advT); advT = null; if (step < STEPS - 1) { step++; draw(); } else finish(); } // clearTimeout: a pick's auto-advance timer must never double-fire past a beat when the user taps Next first\n    function finish() {\n      S.profile = S.profile || {}; var P = S.profile;\n      P.vibe = data.vibe || P.vibe || \"\"; P.lowStart = (data.vibe === \"overwhelmed\" || data.vibe === \"stuck\") || !!P.lowStart;\n      P.messRoom = data.messRoom || P.messRoom || \"\"; if (data.pactAt) P.pact = { ts: data.pactAt }; P.set = true;\n      if (data.block && data.block !== \"none\") P.block = { type: data.block, ts: Date.now() }; // the blocker blessing (P0-a): shape only, never content — cashed by the Doorway node on days 2-7\n      var _hr = new Date().getHours(); P.openBand = P.openBand || ((_hr >= 22 || _hr < 4) ? \"night\" : _hr < 9 ? \"early\" : _hr < 17 ? \"day\" : \"evening\"); // unfakeable first-open truth — the finale's skip-proof fallback\n      if (!S.habits || !S.habits.length) S.habits = DEFAULT_HABITS.slice();\n      S.guide = S.guide || { mode: \"guided\", seedTier: 0, unlocked: [], cache: {}, offeredK: null };\n      S.guide.mode = \"guided\"; S.guide.unlocked = (S.guide.unlocked && S.guide.unlocked.length) ? S.guide.unlocked : [0];\n      if (data.vibe) { // placement-by-attempt seed: the vibe answer warm-starts the appetite dial (appetiteUpdate keeps a seeded level while completionRate7d===null, then real data takes over)\n        var _lv = data.vibe === \"thriving\" ? \"high\" : data.vibe === \"coasting\" ? \"floor\" : \"low\";\n        var _as = S.guide.appetiteState = S.guide.appetiteState || { level: _lv, nodeCap: 2, modeTarget: \"guided\", stateAge: 0, stateLockedByUser: false, inviteDeclineCount: 0, lastDeclineK: null, lastInviteSentK: null };\n        if (!_as.stateLockedByUser) { _as.level = _lv; _as.nodeCap = _appCap(_lv); }\n      }\n      if (((S.game || {}).total || 0) <= 60 && !S.guide.fd) S.guide.fd = { k: todayK() }; // FIVE STONES (F1, David 2026-07-02): a brand-new save gets the hand-authored first-day trail; a Redo-setup on a real save (spark total > 60) never does\n      save(); ov.remove();\n      try { renderAll(); viewK = todayK(); zoomMode = \"day\"; openJourney(); } catch (e) {}\n    }\n    function stdFoot(primaryLabel, showBack) {\n      var b = add(foot, \"button\", \"ob-btn\" + (step === STEPS - 1 ? \" go\" : \"\"), primaryLabel); b.onclick = next;\n      if (showBack) { var bk = add(foot, \"button\", \"ob-back\", \"◂ back\"); bk.onclick = function () { step--; draw(); }; }\n      var skip = add(foot, \"button\", \"ob-skip\", \"skip\"); skip.onclick = finish; // skip must still seed defaults via finish() — bailing early used to strand the app half-initialized (David 2026-07-02)\n    }\n    function taskDone() {\n      if (data.taskDone) return; data.taskDone = true;\n      var _chL = data.vibe === \"overwhelmed\" ? \"Pick one thing up off the floor\" : data.vibe === \"thriving\" ? \"Pick three things up off the floor\" : \"Pick two things up off the floor\"; // sized by the vibe read — the log title matches what was actually asked\n      try { choreMark({ id: \"declutter\", l: _chL }); } catch (e) {} // choreMark already grants earn(10) — top up to land in the 15-20 first-win range the spec calls for, not double-stack a second full earn\n      try { earn(8, { label: \"onboard-task-bonus\" }); } catch (e) {}\n      draw();\n    }\n    function draw() {\n      barDs.forEach(function (d, di) { d.className = di <= step ? \"on\" : \"\"; }); body.innerHTML = \"\"; foot.innerHTML = \"\";\n      body.className = (step === 0 || step === 1 || step === 2 || step === 4 || step === 6) ? \"ob-body center\" : \"ob-body\";\n      if (step === 0) { add(body, \"i\", \"ti ti-sparkles ob-spk\"); var f = add(body, \"div\", \"ob-face\"); add(f, \"span\", \"ob-eye l\"); add(f, \"span\", \"ob-eye r\"); add(body, \"div\", \"ob-q\", \"Hi, I'm Sage.\"); add(body, \"div\", \"ob-sb\", \"what I'm about to show you gives you real powers. this is no joke.\"); stdFoot(\"Let's go ▸\", false); return; }\n      if (step === 1) { add(body, \"i\", \"ti ti-shield-star ob-spk\"); add(body, \"div\", \"ob-q\", \"Every real thing you do, I remember — and your world grows.\"); add(body, \"div\", \"ob-sb\", \"small things count. let's prove it — 90 seconds.\"); stdFoot(\"Next ▸\", false); return; }\n      if (step === 5) { // PACT — moved AFTER the first win (2026-07-03): give-before-take made true; the promise is now backed by evidence, not a salesman's check\n        add(body, \"div\", \"ob-q\", \"One rule — now that you've seen it's real.\"); add(body, \"div\", \"ob-sb\", \"I will never lie to you. Hold to promise the same back.\");\n        var pactWrap = add(body, \"div\"); pactWrap.style.cssText = \"margin-top:22px;\";\n        var pb = add(pactWrap, \"button\", \"ob-btn\"); pb.style.cssText = \"position:relative;overflow:hidden;width:100%;\";\n        var fill = add(pb, \"span\"); fill.style.cssText = \"position:absolute;left:0;top:0;bottom:0;width:\" + (data.pactAt ? \"100\" : \"0\") + \"%;background:rgba(255,255,255,.32);z-index:0;\";\n        add(pb, \"span\", null, data.pactAt ? \"✓ promised\" : \"hold to promise\").style.cssText = \"position:relative;z-index:1;\";\n        var holdT = null, holdDone = !!data.pactAt;\n        function release() { if (holdDone) return; clearTimeout(holdT); fill.style.transition = \"width .25s ease\"; fill.style.width = \"0%\"; }\n        if (!data.pactAt) {\n          pb.addEventListener(\"pointerdown\", function () { holdDone = false; fill.style.transition = \"width 1.2s linear\"; requestAnimationFrame(function () { fill.style.width = \"100%\"; }); holdT = setTimeout(function () { holdDone = true; data.pactAt = Date.now(); try { if (navigator.vibrate) navigator.vibrate(14); } catch (e) {} draw(); }, 1200); });\n          pb.addEventListener(\"pointerup\", release); pb.addEventListener(\"pointercancel\", release); pb.addEventListener(\"pointerleave\", release);\n        }\n        if (data.pactAt) { stdFoot(\"Next ▸\", true); } else { var skip = add(foot, \"button\", \"ob-skip\", \"skip\"); skip.onclick = finish; }\n        return;\n      }\n      if (step === 2) { // §12 frame 12 — the VIBE BEAT, now ANSWERED ALOUD (2026-07-03): Sage replies to the exact pick, sized — the four states stop collapsing to one silent boolean; the reply IS the proof the answer landed\n        var av = add(body, \"div\", \"ob-ava\"); av.innerHTML = '<i class=\"ti ti-sparkles\"></i>';\n        add(body, \"div\", \"ob-q\", \"What's closest to the truth right now?\").style.cssText = \"font-size:26px;font-weight:800;text-align:center;line-height:1.2;\";\n        add(body, \"div\", \"ob-sb\", \"no right answers\").style.cssText = \"text-align:center;margin-top:6px;\";\n        var vw = add(body, \"div\"); vw.style.cssText = \"width:100%;display:flex;flex-direction:column;gap:12px;margin-top:22px;text-align:left;\";\n        [[\"thriving\", \"Burning\", \"things move — I want more\", \"ti-flame\", \"#ff8a3a\", \"high\"],\n         [\"coasting\", \"Flowing\", \"day after day, on autopilot\", \"ti-ripple\", \"#48b8e0\", \"mid\"],\n         [\"stuck\", \"Stuck\", \"I know what to do — I don't\", \"ti-anchor\", \"#ff5fa8\", \"mid\"],\n         [\"overwhelmed\", \"Drowning\", \"too much of everything\", \"ti-droplet\", \"#7a9aff\", \"low\"]].forEach(function (o) {\n          var on3 = data.vibe === o[0], r = add(vw, \"div\", \"k-row\" + (on3 ? \" lit\" : \"\"));\n          r.style.cssText = \"--kc:\" + mixHex(o[4], \"#160510\", 0.28) + \";--kt:\" + mixHex(o[4], \"#0d0410\", 0.86) + \";--kA:\" + o[4] + \";--kB:\" + mixHex(o[4], \"#160510\", 0.24) + \";--ki:\" + mixHex(o[4], \"#0d0410\", 0.76) + \";--ks:\" + mixHex(o[4], \"#b39ab0\", 0.5) + \";\";\n          r.innerHTML = '<i class=\"ti ' + o[3] + '\"></i><div style=\"flex:1;min-width:0;\"><div class=\"kr-t\">' + o[1] + '</div><div class=\"kr-s\">' + o[2] + '</div></div>' + (on3 ? '<i class=\"ti ti-check kr-chk\"></i>' : '');\n          r.onclick = function () { if (data.vibe === o[0]) return; data.vibe = o[0]; data.energy = o[5]; draw(); clearTimeout(advT); advT = setTimeout(next, 1700); };\n        });\n        var VR = { thriving: \"Good. Let's spend some of that — right now.\", coasting: \"Steady. One real thing on purpose — that changes a day.\", stuck: \"I know that one. Knowing isn't the problem — we'll just move one small thing.\", overwhelmed: \"Okay. Then we go small today — I'll carry the rest.\" };\n        if (data.vibe) { add(body, \"div\", \"ob-sb\", VR[data.vibe]).style.cssText = \"text-align:center;margin-top:16px;font-weight:700;color:#f0e6ef;\"; }\n        else add(body, \"div\", \"ob-sb\", \"your pick ignites — like a matched block\").style.cssText = \"text-align:center;margin-top:16px;opacity:.65;\";\n        var skip3 = add(foot, \"button\", \"ob-skip\", \"skip\"); skip3.onclick = finish;\n        return;\n      }\n      if (step === 3) { // THE TASK, SIZED BY THE READ (placement-by-attempt, 2026-07-03): Drowning = one thing, Burning = three-against-the-clock — the same state-question finally has teeth on the very next screen. Room grid is dead; the room is asked AFTER the win, from the body (\"where were you just standing?\"), so messRoom is revealed, not surveyed.\n        if (!data.taskDone) {\n          add(body, \"i\", \"ti ti-arrow-big-down-lines ob-spk\").style.marginTop = \"18px\";\n          add(body, \"div\", \"ob-q\", data.vibe === \"overwhelmed\" ? \"Pick ONE thing up off the floor. That's the whole ask.\" : data.vibe === \"thriving\" ? \"Three things off the floor — beat thirty seconds. Go.\" : \"Pick two things up off the floor. I'll wait.\");\n          add(body, \"div\", \"ob-sb\", \"really — go do it, then tap Done.\");\n          var db = add(foot, \"button\", \"ob-btn go\", \"Done ✓\"); db.onclick = taskDone;\n          var skip4 = add(foot, \"button\", \"ob-skip\", \"skip\"); skip4.onclick = finish;\n        } else {\n          add(body, \"i\", \"ti ti-sparkles ob-spk\"); add(body, \"div\", \"ob-q\", \"+18 Spark.\");\n          add(body, \"div\", \"ob-sb\", \"that's it. that's the whole game — real things, remembered.\");\n          add(body, \"div\", \"ob-sb\", \"Where were you just standing?\").style.cssText = \"margin-top:20px;font-weight:700;color:#f0e6ef;\";\n          var rr = add(body, \"div\", \"ob-row\");\n          [\"Bedroom\", \"Kitchen\", \"Living room\", \"Desk / office\", \"Bathroom\"].forEach(function (r) { var c = chip(rr, r, data.messRoom === r); c.onclick = function () { data.messRoom = r; draw(); }; });\n          if (data.messRoom) add(body, \"div\", \"ob-sb\", \"Noted. That corner's on my list for you now.\").style.cssText = \"margin-top:10px;opacity:.85;\";\n          stdFoot(\"Next ▸\", false);\n        }\n        return;\n      }\n      if (step === 4) { // THE BLOCKER BLESSING (P0-a, 2026-07-03): the shape of the wall, never the content — three fixed chips (RU-safe), the reply is a promise the Doorway node cashes on days 2-7\n        var av4 = add(body, \"div\", \"ob-ava\"); av4.innerHTML = '<i class=\"ti ti-sparkles\"></i>';\n        add(body, \"div\", \"ob-q\", \"One real thing you've been circling.\").style.cssText = \"font-size:24px;font-weight:800;text-align:center;line-height:1.2;\";\n        add(body, \"div\", \"ob-sb\", \"I don't need to know what it is — just the shape of the wall.\").style.cssText = \"text-align:center;margin-top:6px;\";\n        var bw = add(body, \"div\"); bw.style.cssText = \"width:100%;display:flex;flex-direction:column;gap:12px;margin-top:22px;text-align:left;\";\n        [[\"fear\", \"It scares me to even look\", \"ti-flame\", \"#ff8a3a\"],\n         [\"overwhelm\", \"Too big — I don't know where it starts\", \"ti-mountain\", \"#7a9aff\"],\n         [\"wound\", \"An old bad time with it\", \"ti-anchor\", \"#c4607f\"],\n         [\"none\", \"Nothing like that — I'm just here\", \"ti-cloud\", \"#48b8e0\"]].forEach(function (o) {\n          var on4 = data.block === o[0], r = add(bw, \"div\", \"k-row\" + (on4 ? \" lit\" : \"\"));\n          r.style.cssText = \"--kc:\" + mixHex(o[3], \"#160510\", 0.28) + \";--kt:\" + mixHex(o[3], \"#0d0410\", 0.86) + \";--kA:\" + o[3] + \";--kB:\" + mixHex(o[3], \"#160510\", 0.24) + \";--ki:\" + mixHex(o[3], \"#0d0410\", 0.76) + \";--ks:\" + mixHex(o[3], \"#b39ab0\", 0.5) + \";\";\n          r.innerHTML = '<i class=\"ti ' + o[2] + '\"></i><div style=\"flex:1;min-width:0;\"><div class=\"kr-t\">' + o[1] + '</div></div>' + (on4 ? '<i class=\"ti ti-check kr-chk\"></i>' : '');\n          r.onclick = function () { if (data.block === o[0]) return; data.block = o[0]; draw(); clearTimeout(advT); advT = setTimeout(next, 1900); };\n        });\n        var BR = { fear: \"Then we never look at the whole thing — just the edge. Tomorrow I'll bring it so small it can't scare you.\", overwhelm: \"Then we never start with the whole thing — just the first corner. Tomorrow I'll bring you one.\", wound: \"Then we go gently — with a way out at every step. You set the pace.\", none: \"Good. Then we build forward.\" };\n        if (data.block) { add(body, \"div\", \"ob-sb\", BR[data.block]).style.cssText = \"text-align:center;margin-top:16px;font-weight:700;color:#f0e6ef;\"; stdFoot(\"Next ▸\", false); }\n        else { var skipB = add(foot, \"button\", \"ob-skip\", \"skip\"); skipB.onclick = finish; }\n        return;\n      }\n      if (step === 6) {\n        add(body, \"div\", \"ob-world\").innerHTML = '<i class=\"ti ti-sparkles\"></i>';\n        add(body, \"div\", \"ob-q\", \"Plant your first seed.\"); add(body, \"div\", \"ob-sb\", \"free — you already earned it.\");\n        if (!data.seeded) {\n          var plantBtn = add(body, \"button\", \"ob-btn\", \"🌱 Plant\"); plantBtn.style.marginTop = \"16px\";\n          plantBtn.onclick = function () { try { plantGarden(); } catch (e) {} data.seeded = true; draw(); };\n        } else {\n          add(body, \"div\", \"ob-sb\", \"planted — your world grows with you now.\").style.marginTop = \"10px\";\n          var startBtn = add(foot, \"button\", \"ob-btn go\", \"Start ▸\"); startBtn.onclick = finish;\n        }\n        return;\n      }\n    }\n    draw();\n  }\n  var VIRTUES = [\n    { k: \"zest\", l: \"Zest\", e: \"⚡\", c: \"#ff8a1e\", grow: \"move your body\" },\n    { k: \"disc\", l: \"Discipline\", e: \"⚔️\", c: \"#3a9ae6\", grow: \"show up to a habit or deep work\" },\n    { k: \"love\", l: \"Love\", e: \"❤️\", c: \"#ff4fa0\", grow: \"reach out to someone you love\" },\n    { k: \"courage\", l: \"Courage\", e: \"🦁\", c: \"#ffcf3a\", grow: \"ship the thing you're avoiding\" },\n    { k: \"wisdom\", l: \"Wisdom\", e: \"🦉\", c: \"#7a6cf0\", grow: \"read or study something real\" },\n    { k: \"curiosity\", l: \"Curiosity\", e: \"🔭\", c: \"#23c98a\", grow: \"make or explore something new\" },\n    { k: \"gratitude\", l: \"Gratitude\", e: \"🙏\", c: \"#ff7ab0\", grow: \"note what you're grateful for\" },\n    { k: \"hope\", l: \"Hope\", e: \"🌅\", c: \"#48d0e0\", grow: \"plan tomorrow\" }\n  ];\n  var VCLASS = { zest: \"The Vital\", disc: \"The Disciplined\", love: \"The Lover\", courage: \"The Brave\", wisdom: \"The Sage\", curiosity: \"The Explorer\", gratitude: \"The Grateful\", hope: \"The Hopeful\" };\n  function virtueOf(e) {\n    var t = (e.title || \"\").toLowerCase(), c = e.catK || TITLE2CAT[t] || (e.habitId ? HABIT2CAT[e.habitId] : null);\n    if (/gratitude|journal|reflect|affirmation/.test(t)) return \"gratitude\";\n    if (/^plan|planning/.test(t)) return \"hope\";\n    if (e.habitId === \"send\" || /ship|send|outreach|publish|pitch|apply/.test(t)) return \"courage\";\n    if (e.habitId === \"read\" || /read|study|research|learn|language|podcast/.test(t)) return \"wisdom\";\n    if (/create|midjourney|design|video|music|content|write|draw|paint|photo|craft|guitar|piano|sing/.test(t)) return \"curiosity\";\n    if (c === \"energy\") return \"zest\";\n    if (c === \"love\") return \"love\";\n    if (c === \"hobby\") return \"curiosity\";\n    if (c === \"work\") return \"disc\";\n    return null;\n  }\n\n  var S;\n  function fresh() { return { habits: DEFAULT_HABITS.slice(), habitDone: {}, blocks: {}, log: {}, lastTidy: null, timers: [], baseline: null, profile: null, game: { spark: 0, total: 0, ups: {}, garden: [] } }; }\n  function load() { var _rawLoad = localStorage.getItem(KEY); try { S = JSON.parse(_rawLoad) || fresh(); if (S.v == null) S.v = 0; var prevSchema = S.v; S.habits = S.habits && S.habits.length ? S.habits : DEFAULT_HABITS.slice(); S.habitDone = S.habitDone || {}; S.blocks = S.blocks || {}; S.log = S.log || {}; S.timers = S.timers || []; S.habits = S.habits.filter(function (h) { return h.id !== \"send\"; }); S.habits.forEach(function (h) { if (!h.type) h.type = \"build\"; if (h.per == null) h.per = 0; if (!h.color) h.color = \"#8a5cf0\"; }); S.game = S.game || { spark: 0, total: 0, ups: {} }; S.game.ups = S.game.ups || {}; S.game.garden = S.game.garden || []; S.brain = S.brain || { engine: \"off\", key: \"\" }; S.microState = S.microState || {}; S.mood = S.mood || {}; S.acts = S.acts || []; S.acts.forEach(function (a) { if (a.children == null) a.children = []; }); /* sub-habits: a custom activity can own children (Deep work → Define the ONE thing, No phone…) — default [] so old data is safe (David 2026-06-27) */ S.bk = S.bk || {}; S.guide = S.guide || { mode: \"off\", seedTier: 0, unlocked: [], cache: {}, offeredK: null }; S.tools = S.tools || {}; S.tools.use = S.tools.use || {}; S.tools.last = S.tools.last || {}; S.tools.fav = S.tools.fav || []; S.tools.recents = S.tools.recents || []; if (S.voiceDebug == null) S.voiceDebug = false; S.voiceDebug = false; /* audio confirmed working (David 2026-07-01) → diagnostic OFF; can re-enable in Settings if a tool ever misbehaves */ S.audio = S.audio || { voice: 1, bg: 1 }; if (S.audio.voice == null) S.audio.voice = 1; if (S.audio.bg == null) S.audio.bg = 1; if (S.audio.bed == null) S.audio.bed = \"pad\"; if (!S.audioMigPad) { S.audioMigPad = 1; S.audio.bed = \"pad\"; } /* one-time: default everyone to the peaceful pad David preferred (David 2026-07-01) */ if (S.audio.appMusic == null) S.audio.appMusic = false; if (!S.audioMigMusicOff) { S.audioMigMusicOff = 1; S.audio.appMusic = false; } /* David 2026-07-02: NO background noise when the app opens — whole-app music is OFF by default (one-time migration turns it off for existing saves too); the Sound panel toggle stays for opting back in. Tool beds (the pad inside meditation/breath) are untouched. */ /* WISDOM TOOLBOX (TB-STATE, David 2026-06-28): additive top-level store keyed by toolId — use[id] = COMPLETED reps (Willingness<3 / Habit<12 